-- SeedConfigSettings.sql
  -- Seed data for AAAA_ConfigSettings table (shared settings table, column names preserved exactly from SQL Server source)
  -- MuniName row (ID=10) set to 'Mnquma Local Municipality' for this deployment

SELECT setval(pg_get_serial_sequence('"AAAA_ConfigSettings"', 'ConfigSett_ID'), GREATEST(2409, (SELECT COALESCE(MAX("ConfigSett_ID"),0) FROM "AAAA_ConfigSettings")));